export const ERR_NON_ADJACENT = 'Cannot connect non-adjacent islands';
export const ERR_MAX_PER_PAIR = 'Max 2 bridges per pair';
export const ERR_EXCEED = 'Island would exceed its number';
export const ERR_CROSS = 'Bridges would cross';

function isAligned(a, b) {
  return a.x === b.x || a.y === b.y;
}

export function canonicalBridgeKey(from, to) {
  const a = { x: from.x, y: from.y };
  const b = { x: to.x, y: to.y };
  const first = a.x < b.x || (a.x === b.x && a.y <= b.y) ? a : b;
  const second = first === a ? b : a;
  return `${first.x},${first.y},${second.x},${second.y}`;
}

function parseKey(key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  return { x1, y1, x2, y2 };
}

function between(v, a, b) {
  return v > Math.min(a, b) && v < Math.max(a, b);
}

function hasBlockingIsland(islands, a, b) {
  if (!isAligned(a, b)) return true;
  if (a.x === b.x) {
    const x = a.x;
    return islands.some((p) => p.id !== a.id && p.id !== b.id && p.x === x && between(p.y, a.y, b.y));
  }
  const y = a.y;
  return islands.some((p) => p.id !== a.id && p.id !== b.id && p.y === y && between(p.x, a.x, b.x));
}

export function areAdjacent(islands, a, b) {
  if (!a || !b) return false;
  if (a.id === b.id) return false;
  if (!isAligned(a, b)) return false;
  return !hasBlockingIsland(islands, a, b);
}

function segmentCrosses(segA, segB) {
  // Only consider crossing of perpendicular interior points (not sharing endpoints).
  const a = segA;
  const b = segB;

  const aVert = a.x1 === a.x2;
  const bVert = b.x1 === b.x2;
  if (aVert === bVert) return false;

  const v = aVert ? a : b;
  const h = aVert ? b : a;

  const ix = v.x1;
  const iy = h.y1;

  const vMinY = Math.min(v.y1, v.y2);
  const vMaxY = Math.max(v.y1, v.y2);
  const hMinX = Math.min(h.x1, h.x2);
  const hMaxX = Math.max(h.x1, h.x2);

  // intersection must be strictly inside both segments (not at endpoints)
  const vInterior = iy > vMinY && iy < vMaxY;
  const hInterior = ix > hMinX && ix < hMaxX;
  if (!vInterior || !hInterior) return false;

  // exclude if intersection equals any endpoint (extra safety)
  const endpoints = [
    `${a.x1},${a.y1}`,
    `${a.x2},${a.y2}`,
    `${b.x1},${b.y1}`,
    `${b.x2},${b.y2}`
  ];
  if (endpoints.includes(`${ix},${iy}`)) return false;

  return true;
}

export function bridgesWouldCross(bridges, from, to) {
  const key = canonicalBridgeKey(from, to);
  const { x1, y1, x2, y2 } = parseKey(key);
  const newSeg = { x1, y1, x2, y2 };

  for (const [k, count] of bridges.entries()) {
    if (!count) continue;
    if (k === key) continue;
    const seg = parseKey(k);

    // sharing endpoints never counts as crossing
    const sharesEndpoint =
      (seg.x1 === x1 && seg.y1 === y1) ||
      (seg.x2 === x1 && seg.y2 === y1) ||
      (seg.x1 === x2 && seg.y1 === y2) ||
      (seg.x2 === x2 && seg.y2 === y2) ||
      (seg.x1 === x1 && seg.y1 === y1) ||
      (seg.x2 === x2 && seg.y2 === y2);

    if (sharesEndpoint) continue;
    if (segmentCrosses(newSeg, seg)) return true;
  }
  return false;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) counts.set(isl.id, 0);

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = islands.find((p) => p.x === x1 && p.y === y1);
    const b = islands.find((p) => p.x === x2 && p.y === y2);
    if (!a || !b) continue;
    counts.set(a.id, (counts.get(a.id) ?? 0) + n);
    counts.set(b.id, (counts.get(b.id) ?? 0) + n);
  }

  return counts;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  if (!areAdjacent(islands, from, to)) {
    return { valid: false, error: ERR_NON_ADJACENT };
  }

  const key = canonicalBridgeKey(from, to);
  const current = bridges.get(key) ?? 0;
  const next = current + delta;

  if (next < 0) return { valid: true, error: null };
  if (next > 2) return { valid: false, error: ERR_MAX_PER_PAIR };

  if (next > 0 && bridgesWouldCross(bridges, from, to)) {
    return { valid: false, error: ERR_CROSS };
  }

  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = (counts.get(from.id) ?? 0) + delta;
  const toCount = (counts.get(to.id) ?? 0) + delta;

  if (fromCount > from.value || toCount > to.value) {
    return { valid: false, error: ERR_EXCEED };
  }

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (!islands.length) return true;

  const adj = new Map();
  for (const isl of islands) adj.set(isl.id, []);

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = islands.find((p) => p.x === x1 && p.y === y1);
    const b = islands.find((p) => p.x === x2 && p.y === y2);
    if (!a || !b) continue;
    adj.get(a.id).push(b.id);
    adj.get(b.id).push(a.id);
  }

  const start = islands[0].id;
  const seen = new Set([start]);
  const stack = [start];
  while (stack.length) {
    const cur = stack.pop();
    for (const nb of adj.get(cur) || []) {
      if (!seen.has(nb)) {
        seen.add(nb);
        stack.push(nb);
      }
    }
  }

  return seen.size === islands.length;
}

export function isVictory(islands, bridges) {
  // Ensure no crossings (defensive)
  const keys = [...bridges.entries()].filter(([, n]) => n > 0).map(([k]) => k);
  for (let i = 0; i < keys.length; i++) {
    const a = parseKey(keys[i]);
    for (let j = i + 1; j < keys.length; j++) {
      const b = parseKey(keys[j]);
      if (segmentCrosses(a, b)) return false;
    }
  }

  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) ?? 0) !== isl.value) return false;
  }

  return checkConnectivity(islands, bridges);
}
EOF

cat > src/App.jsx <<'EOF'
import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles } from './data/puzzles.js';
import {
  canonicalBridgeKey,
  canAddBridge,
  computeCurrentCounts,
  isVictory
} from './utils/hashiLogic.js';

const GRID = 40;
const SVG_W = 800;
const SVG_H = 600;

function islandById(islands, id) {
  return islands.find((i) => i.id === id) || null;
}

function bridgeKeyToEndpoints(key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  return { x1, y1, x2, y2 };
}

function findNextIsland(islands, fromId, dir) {
  const from = islandById(islands, fromId);
  if (!from) return fromId;

  let best = null;
  for (const isl of islands) {
    if (isl.id === from.id) continue;

    if (dir === 'left' && isl.y === from.y && isl.x < from.x) {
      const dist = from.x - isl.x;
      if (!best || dist < best.dist) best = { id: isl.id, dist };
    }
    if (dir === 'right' && isl.y === from.y && isl.x > from.x) {
      const dist = isl.x - from.x;
      if (!best || dist < best.dist) best = { id: isl.id, dist };
    }
    if (dir === 'up' && isl.x === from.x && isl.y < from.y) {
      const dist = from.y - isl.y;
      if (!best || dist < best.dist) best = { id: isl.id, dist };
    }
    if (dir === 'down' && isl.x === from.x && isl.y > from.y) {
      const dist = isl.y - from.y;
      if (!best || dist < best.dist) best = { id: isl.id, dist };
    }
  }

  return best ? best.id : fromId;
}

function applyToggleBridge(islands, bridges, from, to) {
  const key = canonicalBridgeKey(from, to);
  const current = bridges.get(key) ?? 0;
  const next = (current + 1) % 3; // 0->1->2->0

  // We'll validate only when increasing (0->1,1->2). For 2->0 always allow.
  if (next === 0) {
    const nextMap = new Map(bridges);
    nextMap.delete(key);
    return { ok: true, bridges: nextMap, error: null };
  }

  const delta = next - current;
  const res = canAddBridge(islands, bridges, from, to, delta);
  if (!res.valid) return { ok: false, bridges, error: res.error };

  const nextMap = new Map(bridges);
  nextMap.set(key, next);
  return { ok: true, bridges: nextMap, error: null };
}

export default function App() {
  const [puzzleIdx, setPuzzleIdx] = useState(0);
  const puzzle = puzzles[puzzleIdx];
  const islands = puzzle.islands;

  const [bridges, setBridges] = useState(() => new Map());
  const [mouseSelectedId, setMouseSelectedId] = useState(null);

  const [cursorId, setCursorId] = useState(islands[0]?.id ?? 0);
  const [kbdSelectedId, setKbdSelectedId] = useState(null);

  const [error, setError] = useState(null);

  const rootRef = useRef(null);

  useEffect(() => {
    // When puzzle changes, fully reset bridges & selection.
    setBridges(new Map());
    setMouseSelectedId(null);
    setKbdSelectedId(null);
    setError(null);
    setCursorId(puzzles[puzzleIdx].islands[0]?.id ?? 0);
  }, [puzzleIdx]);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  function clearErrorOnValidMove() {
    if (error) setError(null);
  }

  function onIslandClick(isl) {
    if (victory) return;

    if (mouseSelectedId === null) {
      setMouseSelectedId(isl.id);
      return;
    }

    if (mouseSelectedId === isl.id) {
      setMouseSelectedId(null);
      return;
    }

    const from = islandById(islands, mouseSelectedId);
    const to = isl;
    if (!from || !to) {
      setMouseSelectedId(null);
      return;
    }

    const res = applyToggleBridge(islands, bridges, from, to);
    if (!res.ok) {
      setError(res.error);
    } else {
      clearErrorOnValidMove();
      setBridges(res.bridges);
    }

    setMouseSelectedId(null);
  }

  function removeBridgeBetween(from, to) {
    if (victory) return;
    const key = canonicalBridgeKey(from, to);
    if (!(bridges.get(key) > 0)) return;

    const next = new Map(bridges);
    next.delete(key);
    setBridges(next);
    clearErrorOnValidMove();
  }

  function onKeyDown(e) {
    const k = e.key;
    if (k === 'ArrowLeft' || k === 'ArrowRight' || k === 'ArrowUp' || k === 'ArrowDown') {
      e.preventDefault();
      const dir =
        k === 'ArrowLeft'
          ? 'left'
          : k === 'ArrowRight'
            ? 'right'
            : k === 'ArrowUp'
              ? 'up'
              : 'down';
      setCursorId((cur) => findNextIsland(islands, cur, dir));
      return;
    }

    if (k === 'Escape') {
      e.preventDefault();
      setKbdSelectedId(null);
      return;
    }

    if (k === 'Enter') {
      e.preventDefault();
      if (victory) return;

      if (kbdSelectedId === null) {
        setKbdSelectedId(cursorId);
        return;
      }

      if (kbdSelectedId === cursorId) {
        setKbdSelectedId(null);
        return;
      }

      const from = islandById(islands, kbdSelectedId);
      const to = islandById(islands, cursorId);
      const res = applyToggleBridge(islands, bridges, from, to);
      if (!res.ok) {
        setError(res.error);
      } else {
        clearErrorOnValidMove();
        setBridges(res.bridges);
      }
      setKbdSelectedId(null);
    }
  }

  const selectedId = mouseSelectedId ?? kbdSelectedId;

  const bridgeLines = [];
  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = bridgeKeyToEndpoints(key);
    const a = { x: x1, y: y1 };
    const b = { x: x2, y: y2 };

    const px1 = a.x * GRID;
    const py1 = a.y * GRID;
    const px2 = b.x * GRID;
    const py2 = b.y * GRID;

    const isHoriz = py1 === py2;
    const offset = 4;

    const mkLine = (dx, dy, idx) => (
      <line
        key={`${key}-${idx}`}
        x1={px1 + dx}
        y1={py1 + dy}
        x2={px2 + dx}
        y2={py2 + dy}
        stroke="#0f0"
        strokeWidth={3}
        shapeRendering="crispEdges"
        onContextMenu={(e) => {
          e.preventDefault();
          const from = islands.find((i) => i.x === x1 && i.y === y1);
          const to = islands.find((i) => i.x === x2 && i.y === y2);
          if (from && to) removeBridgeBetween(from, to);
        }}
        onClick={(e) => {
          if (e.ctrlKey) {
            e.preventDefault();
            const from = islands.find((i) => i.x === x1 && i.y === y1);
            const to = islands.find((i) => i.x === x2 && i.y === y2);
            if (from && to) removeBridgeBetween(from, to);
          }
        }}
      />
    );

    if (n === 1) {
      bridgeLines.push(mkLine(0, 0, 0));
    } else if (n === 2) {
      if (isHoriz) {
        bridgeLines.push(mkLine(0, -offset, 0));
        bridgeLines.push(mkLine(0, +offset, 1));
      } else {
        bridgeLines.push(mkLine(-offset, 0, 0));
        bridgeLines.push(mkLine(+offset, 0, 1));
      }
    }
  }

  const cursorIsland = islandById(islands, cursorId);
  const cursorPx = cursorIsland ? { x: cursorIsland.x * GRID, y: cursorIsland.y * GRID } : { x: 0, y: 0 };

  return (
    <div
      ref={rootRef}
      tabIndex={0}
      onKeyDown={onKeyDown}
      style={{ outline: 'none' }}
    >
      <div style={{ padding: 8 }}>
        <label>
          Puzzle:{' '}
          <select
            value={puzzleIdx}
            onChange={(e) => setPuzzleIdx(Number(e.target.value))}
            style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace' }}
          >
            <option value={0}>Easy</option>
            <option value={1}>Medium</option>
            <option value={2}>Hard</option>
          </select>
        </label>{' '}
        <button
          onClick={() => {
            setBridges(new Map());
            setMouseSelectedId(null);
            setKbdSelectedId(null);
            setError(null);
          }}
          style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace' }}
        >
          Reset
        </button>
      </div>

      {error ? <div className="error-message" style={{ padding: '0 8px 8px 8px' }}>{error}</div> : null}
      {victory ? <div className="victory-banner" style={{ padding: '0 8px 8px 8px' }}>SOLVED!</div> : null}

      <svg
        width={SVG_W}
        height={SVG_H}
        style={{ position: 'absolute', left: 0, top: 0 }}
        onContextMenu={(e) => e.preventDefault()}
      >
        {/* Bridges first so islands draw on top */}
        {bridgeLines}

        {/* Keyboard cursor (not a circle) */}
        {cursorIsland ? (
          <rect
            x={cursorPx.x - 18}
            y={cursorPx.y - 18}
            width={36}
            height={36}
            fill="none"
            stroke={kbdSelectedId !== null ? '#0f0' : '#0a0'}
            strokeWidth={2}
            strokeDasharray={kbdSelectedId !== null ? '0' : '4 3'}
          />
        ) : null}

        {islands.map((isl) => {
          const cx = isl.x * GRID;
          const cy = isl.y * GRID;
          const isSelected = selectedId === isl.id;
          const cur = counts.get(isl.id) ?? 0;
          const satisfied = cur === isl.value;

          return (
            <g key={isl.id}>
              <circle
                cx={cx}
                cy={cy}
                r={16}
                fill="black"
                stroke={isSelected ? '#9f9' : '#0f0'}
                strokeWidth={2}
                onClick={() => onIslandClick(isl)}
              />
              <text
                x={cx}
                y={cy + 5}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={16}
                fill={satisfied ? '#9f9' : '#0f0'}
                style={{ userSelect: 'none' }}
                onClick={() => onIslandClick(isl)}
              >
                {isl.value}
              </text>
              <text
                x={cx}
                y={cy + 26}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={10}
                fill="#0a0"
                style={{ userSelect: 'none' }}
              >
                {cur}/{isl.value}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}
EOF

