import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles } from './data/puzzles.js';
import { canonicalBridgeKey, canAddBridge, computeCurrentCounts, isVictory } from './utils/hashiLogic.js';

const GRID = 40;
const SVG_W = 800;
const SVG_H = 600;

function islandById(islands, id) {
  return islands.find((i) => i.id === id) || null;
}

function bridgeKeyToEndpoints(key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  return { x1, y1, x2, y2 };
}

function findNextIsland(islands, fromId, dir) {
  const from = islandById(islands, fromId);
  if (!from) return fromId;

  let best = null;
  for (const isl of islands) {
    if (isl.id === from.id) continue;

    if (dir === 'left' && isl.y === from.y && isl.x < from.x) {
      const dist = from.x - isl.x;
      if (!best || dist < best.dist) best = { id: isl.id, dist };
    }
    if (dir === 'right' && isl.y === from.y && isl.x > from.x) {
      const dist = isl.x - from.x;
      if (!best || dist < best.dist) best = { id: isl.id, dist };
    }
    if (dir === 'up' && isl.x === from.x && isl.y < from.y) {
      const dist = from.y - isl.y;
      if (!best || dist < best.dist) best = { id: isl.id, dist };
    }
    if (dir === 'down' && isl.x === from.x && isl.y > from.y) {
      const dist = isl.y - from.y;
      if (!best || dist < best.dist) best = { id: isl.id, dist };
    }
  }

