                y={cy + 26}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={10}
                fill="#0a0"
                style={{ userSelect: 'none' }}
              >
                {cur}/{isl.value}
              </text>
            </g>
          );
        })}
      </svg>

      {/* Overlay UI (does not affect board positioning) */}
      <div
        style={{
          position: 'fixed',
          left: 8,
          top: 8,
          background: 'rgba(0,0,0,0.85)',
          padding: 8,
          border: '1px solid #0f0'
        }}
      >
        <div>
          <label>
            Puzzle:{' '}
            <select
              value={puzzleIdx}
              onChange={(e) => setPuzzleIdx(Number(e.target.value))}
              style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace' }}
            >
              <option value={0}>Easy</option>
              <option value={1}>Medium</option>
              <option value={2}>Hard</option>
            </select>
          </label>{' '}
          <button
            onClick={() => {
              setBridges(new Map());
              setMouseSelectedId(null);
              setKbdSelectedId(null);
              setError(null);
            }}
            style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace' }}
          >
            Reset
          </button>
        </div>

        {error ? (
          <div className="error-message" style={{ marginTop: 8 }}>
            {error}
          </div>
        ) : null}
        {victory ? (
          <div className="victory-banner" style={{ marginTop: 8 }}>
            SOLVED!
          </div>
        ) : null}
      </div>
    </div>
  );
}
